// ===== items art (consumables) =====================================
// Shared local shape helpers (no import/export). Drawn with documented
// Painter primitives + sym only. Each defineIcon already adds panel + outline.

// A glass flask/potion filled with `liquid`. tall=true draws a rounder bulb.
function _flask(p, liquid, tall) {
  const dl = darken(liquid, 0.3), ll = lighten(liquid, 0.4);
  // cork + neck
  p.rect(6, 2, 4, 2, P.woodL);
  p.rect(6, 2, 4, 1, P.bone);
  p.rect(6, 4, 4, 1, P.gray4);
  p.rect(7, 4, 2, 2, P.gray3);
  // bulb
  const cy = tall ? 10 : 9, ry = tall ? 5 : 4;
  p.ellipse(8, cy, 4, ry, dl);
  p.ellipse(8, cy, 3, ry - 1, liquid);
  // liquid surface highlight + glass shine
  p.ellipse(8, cy - ry + 1, 2.4, 1, ll);
  p.px(6, cy - 1, ll);
  p.px(5, cy, P.white);
  p.px(10, cy + 1, dl);
}

// A heraldic shield shape filled with metal `c`, with an emblem hook.
function _shield(p, c) {
  const dc = darken(c, 0.22), lc = lighten(c, 0.28);
  for (let y = 3; y <= 13; y++) {
    const t = (y - 3) / 10;
    let w = 4.4 * (1 - t * 0.5);
    if (y > 10) w *= (14 - y) / 3.5;     // taper to a point at the bottom
    p.hline(8 - w, 7 + w, y, t < 0.45 ? c : dc);
  }
  p.hline(5, 10, 3, lc);                 // top rim light
  p.vline(4, 9, 8, lc);                  // left bevel
}

// A small crystal shard cluster (for shard-themed icons).
function _crystal(p, c) {
  const dc = darken(c, 0.28), lc = lighten(c, 0.35);
  p.ellipse(8, 9, 2.4, 4.4, dc);
  p.ellipse(8, 9, 1.5, 3.4, c);
  p.vline(5, 12, 8, lc);
  p.px(8, 5, P.white);
}

